with open('/root/books/webapp/books.json', 'r', encoding='utf-8') as f:
    books = json.load(f)

existing_ids = {b['id'] for b in books}
added = 0
for new_book in new_books:
    if new_book['id'] not in existing_ids:
        books.append(new_book)
        print(f"Добавлен: id={new_book['id']} — {new_book['title']}")
        added += 1
    else:
        print(f"Уже есть: id={new_book['id']}")

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, indent=2)

print(f'Добавлено: {added}. Всего книг: {len(books)}')
